#!/usr/bin/env bash
#
# Pre-Edit Hook for this operator
# Prevents editing generated files, vendored code, and high-risk files without warning
#
# Usage: Called automatically by Claude Code before file edits
#

set -euo pipefail

FILE="${1:-}"

if [[ -z "$FILE" ]]; then
  echo "Usage: $0 <file-path>"
  exit 1
fi

REPO_ROOT=$(git rev-parse --show-toplevel 2>/dev/null || echo ".")

if [[ "$FILE" = /* ]]; then
  if [[ ! "$FILE" == "$REPO_ROOT"/* ]]; then
    echo "❌ ERROR: File path is outside repository: $FILE"
    exit 1
  fi
  FILE="${FILE#"$REPO_ROOT"/}"
fi

if command -v realpath >/dev/null 2>&1; then
  CANONICAL=$(realpath -m --relative-to="$REPO_ROOT" "$FILE" 2>/dev/null || realpath --relative-to="$REPO_ROOT" "$FILE" 2>/dev/null || echo "")
else
  CANONICAL=""
fi

if [[ -z "$CANONICAL" ]]; then
  if command -v python3 >/dev/null 2>&1; then
    CANONICAL=$(python3 -c "import os.path; print(os.path.relpath(os.path.normpath('$FILE'), '$REPO_ROOT'))" 2>/dev/null || echo "")
  elif command -v python >/dev/null 2>&1; then
    CANONICAL=$(python -c "import os.path; print(os.path.relpath(os.path.normpath('$FILE'), '$REPO_ROOT'))" 2>/dev/null || echo "")
  fi
fi

if [[ -z "$CANONICAL" ]] || [[ "$CANONICAL" == *".."* ]]; then
  echo "❌ ERROR: Invalid file path (contains traversal): $FILE"
  exit 1
fi
FILE="$CANONICAL"
FILE="${FILE#./}"

confirm_or_exit() {
  local prompt="$1"
  echo "$prompt"

  if [[ ! -t 0 ]]; then
    echo "❌ ERROR: Non-interactive environment detected"
    echo "   This operation requires manual confirmation"
    exit 1
  fi

  read -r response
  if [[ ! "$response" =~ ^[Yy]$ ]]; then
    exit 1
  fi
}

# =============================================================================
# GENERATED FILES - BLOCK EDITS
# =============================================================================

if [[ "$FILE" == *"zz_generated."* ]]; then
  echo "❌ BLOCKED: Cannot edit generated file: $FILE"
  echo "   This file is auto-generated by controller-gen."
  echo "   To regenerate: boilerplate/_lib/container-make generate"
  exit 1
fi

# Mock at pkg/dmsclient/mock/mock_dmsclient.go
if [[ "$FILE" == *"/mock/mock_"* ]]; then
  echo "❌ BLOCKED: Cannot edit generated mock: $FILE"
  echo "   This file is auto-generated by mockgen."
  echo "   To regenerate: boilerplate/_lib/container-make generate"
  exit 1
fi

if [[ "$FILE" == deploy/crds/* ]] && [[ "$FILE" == *.yaml ]]; then
  echo "⚠️  WARNING: Editing generated CRD manifest: $FILE"
  echo "   CRDs are generated from API types."
  echo "   Consider editing api/v1alpha1/*.go instead."
  echo "   To regenerate CRDs: make manifests"
  echo ""
  confirm_or_exit "   Continue? (y/N)"
fi

# =============================================================================
# LOCKFILES - WARNING
# =============================================================================

if [[ "$FILE" == "go.sum" ]]; then
  echo "⚠️  WARNING: Editing go.sum directly"
  echo "   This file is managed by 'go mod tidy'."
  confirm_or_exit "   Are you sure you want to edit it manually? (y/N)"
fi

# =============================================================================
# VENDORED CODE - BLOCK EDITS
# =============================================================================

if [[ "$FILE" == vendor/* ]]; then
  echo "❌ BLOCKED: Cannot edit vendored code: $FILE"
  echo "   Vendor directory is managed by go modules."
  echo "   Update dependencies in go.mod instead."
  exit 1
fi

if [[ "$FILE" == boilerplate/* ]] && [[ "$FILE" != boilerplate/update* ]]; then
  echo "⚠️  WARNING: Editing boilerplate file: $FILE"
  echo "   Boilerplate is managed upstream."
  echo "   Local changes may be overwritten by 'make boilerplate-update'."
  confirm_or_exit "   Continue? (y/N)"
fi

# =============================================================================
# HIGH-RISK FILES - WARNING
# =============================================================================

HIGH_RISK_PATTERNS=(
  "*/rbac.go"
  "*/auth*.go"
  "*_rbac.yaml"
  "*/networkpolicy*.go"
  "*[Cc]luster[Rr]ole*.yaml"
  ".tekton/*.yaml"
  "build/Dockerfile"
)

for pattern in "${HIGH_RISK_PATTERNS[@]}"; do
  # shellcheck disable=SC2053
  if [[ "$FILE" == $pattern ]]; then
    echo "⚠️  HIGH-RISK FILE: $FILE"
    echo "   This file affects security or CI/CD."
    echo "   Changes require:"
    echo "   - Careful review"
    echo "   - Test coverage"
    echo "   - Security validation"
    echo ""
    confirm_or_exit "   Continue? (y/N)"
    break
  fi
done

# =============================================================================
# LARGE DIFFS - WARNING
# =============================================================================

if [[ -f "$FILE" ]]; then
  LINES=$(wc -l < "$FILE")
  if (( LINES > 500 )); then
    echo "⚠️  LARGE FILE: $FILE ($LINES lines)"
    echo "   Prefer targeted edits over broad refactors."
    confirm_or_exit "   Continue? (y/N)"
  fi
fi

exit 0
